import java.awt.Color;
import java.awt.Graphics;
import java.awt.image.BufferedImage;
import javax.swing.JFrame;
import javax.swing.JPanel;

public class MandelbrotFractal extends JPanel {

    private static final int WIDTH = 800;
    private static final int HEIGHT = 600;
    private static final int MAX_ITERATIONS = 1000;
    private static final double X_MIN = -2.5;
    private static final double X_MAX = 1.5;
    private static final double Y_MIN = -1.5;
    private static final double Y_MAX = 1.5;

    private BufferedImage image;

    public MandelbrotFractal() {
        super();
        this.image = new BufferedImage(WIDTH, HEIGHT, BufferedImage.TYPE_INT_RGB);
        this.setPreferredSize(new java.awt.Dimension(WIDTH, HEIGHT));
        drawFractal();
    }

    private void drawFractal() {
        double pixelWidth = (X_MAX - X_MIN) / WIDTH;
        double pixelHeight = (Y_MAX - Y_MIN) / HEIGHT;
        for (int x = 0; x < WIDTH; x++) {
            for (int y = 0; y < HEIGHT; y++) {
                double cx = X_MIN + x * pixelWidth;
                double cy = Y_MIN + y * pixelHeight;
                int color = getColor(cx, cy);
                image.setRGB(x, y, color);
            }
        }
    }

    private int getColor(double cx, double cy) {
        double zx = 0;
        double zy = 0;
        int i;
        for (i = 0; i < MAX_ITERATIONS; i++) {
            double zxNew = zx * zx - zy * zy + cx;
            double zyNew = 2 * zx * zy + cy;
            zx = zxNew;
            zy = zyNew;
            if (zx * zx + zy * zy > 4) {
                break;
            }
        }
        if (i == MAX_ITERATIONS) {
            return Color.BLACK.getRGB();
        } else {
            float hue = (float) i / MAX_ITERATIONS;
            return Color.getHSBColor(hue, 1, 1).getRGB();
        }
    }

    @Override
    protected void paintComponent(Graphics g) {
        super.paintComponent(g);
        g.drawImage(image, 0, 0, null);
    }

    public static void main(String[] args) {
        JFrame frame = new JFrame("Mandelbrot Fractal");
        frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
        frame.setContentPane(new MandelbrotFractal());
        frame.pack();
        frame.setVisible(true);
    }
}

