import java.awt.*;
import javax.swing.*;

public class SierpinskiTriangle extends JPanel {

    private int level; // level of recursion

    public SierpinskiTriangle(int level) {
        this.level = level;
        setPreferredSize(new Dimension(600, 600));
    }

    @Override
    protected void paintComponent(Graphics g) {
        super.paintComponent(g);

        int height = getHeight();
        int width = getWidth();
        int triangleHeight = (int) (height * 0.8);
        int triangleWidth = (int) (triangleHeight * Math.sqrt(3) / 2);

        int x = (width - triangleWidth) / 2;
        int y = (height - triangleHeight) / 2;

        drawSierpinskiTriangle(g, level, x, y, triangleWidth, triangleHeight);
    }

    private void drawSierpinskiTriangle(Graphics g, int level, int x, int y, int width, int height) {
        if (level == 0) {
            int[] xPoints = {x, x + width / 2, x + width};
            int[] yPoints = {y + height, y, y + height};
            g.drawPolygon(xPoints, yPoints, 3);
        } else {
            int newWidth = width / 2;
            int newHeight = height / 2;

            drawSierpinskiTriangle(g, level - 1, x, y, newWidth, newHeight);
            drawSierpinskiTriangle(g, level - 1, x + newWidth, y, newWidth, newHeight);
            drawSierpinskiTriangle(g, level - 1, x + newWidth / 2, y + newHeight, newWidth, newHeight);
        }
    }

    public static void main(String[] args) {
        int level = 5;
        SierpinskiTriangle triangle = new SierpinskiTriangle(level);

        JFrame frame = new JFrame("Sierpinski Triangle");
        frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
        frame.getContentPane().add(triangle);
        frame.pack();
        frame.setLocationRelativeTo(null);
        frame.setVisible(true);
    }
}

